// === META ADS TRANSFORM ===
// Input: array de insights da Meta Graph API
// Output: rows prontas para upsert na adv_ads_daily_metrics

const metaItems = $('Meta Ads — Fetch Insights').all();
const rows = [];

for (const item of metaItems) {
  const data = item.json.data || [item.json];
  for (const insight of data) {
    // Extrair conversions e leads das actions
    let conversations = 0;
    let leads = 0;
    if (insight.actions) {
      for (const action of insight.actions) {
        if (action.action_type === 'onsite_conversion.messaging_conversation_started_7d') {
          conversations = parseInt(action.value) || 0;
        }
        if (action.action_type === 'lead') {
          leads = parseInt(action.value) || 0;
        }
      }
    }

    rows.push({
      json: {
        date: insight.date_start || $('Set Date Range').first().json.date_range,
        client: 'META_CLIENT_SLUG',  // TODO: mapear via adv_client_meta_accounts
        account_id: insight.account_id || 'act_PENDING',
        account_name: insight.account_name || null,
        campaign_name: insight.campaign_name || 'unknown',
        adset_name: insight.adset_name || 'unknown',
        ad_name: insight.ad_name || 'unknown',
        objective: insight.objective || null,
        impressions: parseInt(insight.impressions) || 0,
        reach: parseInt(insight.reach) || 0,
        clicks: parseInt(insight.clicks) || 0,
        spend: parseFloat(insight.spend) || 0,
        conversations: conversations,
        leads: leads
      }
    });
  }
}

return rows.length > 0 ? rows : [{ json: { _empty: true, _source: 'meta' } }];

// === GOOGLE ADS TRANSFORM ===
// Input: searchStream response do Google Ads API
// Output: rows prontas para upsert na adv_ads_daily_metrics

const googleItems = $('Google Ads — Fetch Metrics').all();
const rows = [];

for (const item of googleItems) {
  const results = item.json.results || [item.json];
  for (const row of results) {
    const campaign = row.campaign || {};
    const adGroup = row.adGroup || row.ad_group || {};
    const ad = row.adGroupAd?.ad || row.ad_group_ad?.ad || {};
    const metrics = row.metrics || {};

    rows.push({
      json: {
        date: $('Set Date Range').first().json.date_range,
        client: 'GOOGLE_CLIENT_SLUG',  // TODO: mapear via config
        account_id: item.json.customer_id || 'PENDING',
        account_name: null,
        campaign_name: campaign.name || 'unknown',
        adset_name: adGroup.name || 'unknown',
        ad_name: ad.name || 'unknown',
        objective: campaign.advertisingChannelType || campaign.advertising_channel_type || null,
        impressions: parseInt(metrics.impressions) || 0,
        reach: 0,  // Google Ads não tem 'reach' direto neste endpoint
        clicks: parseInt(metrics.clicks) || 0,
        spend: (parseInt(metrics.costMicros || metrics.cost_micros) || 0) / 1000000,
        conversations: 0,
        leads: parseInt(metrics.conversions) || 0
      }
    });
  }
}

return rows.length > 0 ? rows : [{ json: { _empty: true, _source: 'google' } }];

